mapper.select:
SELECT D.PK_NO, D.PERSON_ID, HE.EMPID, HE.LOCAL_NAME, HE.DEPTNO AS DEPT_NO, GET_DEPT_NAME(HE.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPT_NAME, HE.POST_GRADE_NO, GET_GLOBAL_NAME(HE.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS POST_GRADE_NAME, NVL(D.POST_FAMILY, HE.POST_FAMILY) AS POST_FAMILY, GET_GLOBAL_NAME(NVL(D.POST_FAMILY, HE.POST_FAMILY), #{lang, jdbcType=VARCHAR}) AS POST_FAMILY_NAME, D.AR_DATE_STR, D.AR_MONTH_STR, TO_CHAR(D.FROM_TIME, 'YYYY-MM-DD HH24:MI') AS FROM_TIME, TO_CHAR(D.TO_TIME, 'YYYY-MM-DD HH24:MI') AS TO_TIME, TO_CHAR(D.QUANTITY) AS QUANTITY, D.UNIT, TO_CHAR(D.DATE_TYPE) AS DATE_TYPE, D.ITEM_NO, GET_GLOBAL_NAME(D.ITEM_NO, #{lang, jdbcType=VARCHAR}) AS ITEM_NAME, D.SHIFT_NO, GET_GLOBAL_NAME(D.SHIFT_NO, #{lang, jdbcType=VARCHAR}) AS SHIFT_NAME, D.STATUS_CODE, D.STATUS_NAME, D.REMARK, TO_CHAR(D.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, D.CREATED_BY, TO_CHAR(D.UPDATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS UPDATE_DATE, D.UPDATED_BY, TO_CHAR(D.ACTIVITY) AS ACTIVITY, TO_CHAR(D.ORDERNO) AS ORDERNO FROM AR_DETAIL_HTSV D INNER JOIN HR_EMPLOYEE HE ON D.PERSON_ID = HE.PERSON_ID WHERE 1 = 1 AND D.ITEM_NO NOT IN ( '90000295', '90000296', '90000297', '90000298', '90000299', '90000300', '90000301' ) AND EXISTS ( SELECT 1 FROM AR_SUPERVISOR_INFO SI WHERE SI.DEPTNO = HE.DEPTNO AND SI.PERSON_ID = #{adminID, jdbcType=VARCHAR} ) AND HE.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND ( UPPER(HE.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' OR UPPER(HE.LOCAL_NAME) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' )
AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || HE.DEPTNO || ',') > 0
AND TO_DATE(REPLACE(D.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD') >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND TO_DATE(REPLACE(D.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD') <= TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND NVL(D.POST_FAMILY, HE.POST_FAMILY) = #{postFamily, jdbcType=VARCHAR}
AND D.SHIFT_NO = #{shiftNo, jdbcType=VARCHAR}
AND D.ITEM_NO = #{itemNo, jdbcType=VARCHAR}
ORDER BY TO_DATE(REPLACE(D.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD') DESC, HE.EMPID

SELECT D.PK_NO, D.PERSON_ID, HE.EMPID, HE.LOCAL_NAME, HE.DEPTNO AS DEPT_NO, GET_DEPT_NAME(HE.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPT_NAME, HE.POST_GRADE_NO, GET_GLOBAL_NAME(HE.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS POST_GRADE_NAME, NVL(D.POST_FAMILY, HE.POST_FAMILY) AS POST_FAMILY, GET_GLOBAL_NAME(NVL(D.POST_FAMILY, HE.POST_FAMILY), #{lang, jdbcType=VARCHAR}) AS POST_FAMILY_NAME, D.AR_DATE_STR, D.AR_MONTH_STR, TO_CHAR(D.FROM_TIME, 'YYYY-MM-DD HH24:MI') AS FROM_TIME, TO_CHAR(D.TO_TIME, 'YYYY-MM-DD HH24:MI') AS TO_TIME, TO_CHAR(D.QUANTITY) AS QUANTITY, D.UNIT, TO_CHAR(D.DATE_TYPE) AS DATE_TYPE, D.ITEM_NO, GET_GLOBAL_NAME(D.ITEM_NO, #{lang, jdbcType=VARCHAR}) AS ITEM_NAME, D.SHIFT_NO, GET_GLOBAL_NAME(D.SHIFT_NO, #{lang, jdbcType=VARCHAR}) AS SHIFT_NAME, D.STATUS_CODE, D.STATUS_NAME, D.REMARK, TO_CHAR(D.CREATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DATE, D.CREATED_BY, TO_CHAR(D.UPDATE_DATE, 'YYYY-MM-DD HH24:MI:SS') AS UPDATE_DATE, D.UPDATED_BY, TO_CHAR(D.ACTIVITY) AS ACTIVITY, TO_CHAR(D.ORDERNO) AS ORDERNO FROM AR_DETAIL_HTSV D INNER JOIN HR_EMPLOYEE HE ON D.PERSON_ID = HE.PERSON_ID WHERE 1 = 1 AND D.ITEM_NO IN ( '90000295', '90000296', '90000297', '90000298', '90000299', '90000300', '90000301' ) AND EXISTS ( SELECT 1 FROM AR_SUPERVISOR_INFO SI WHERE SI.DEPTNO = HE.DEPTNO AND SI.PERSON_ID = #{adminID, jdbcType=VARCHAR} ) AND HE.CPNY_ID = #{cpnyId, jdbcType=VARCHAR}
AND ( UPPER(HE.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' OR UPPER(HE.LOCAL_NAME) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' )
AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || HE.DEPTNO || ',') > 0
AND TO_DATE(REPLACE(D.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD') >= TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND TO_DATE(REPLACE(D.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD') <= TO_DATE(#{toDate, jdbcType=VARCHAR}, 'YYYY-MM-DD')
AND NVL(D.POST_FAMILY, HE.POST_FAMILY) = #{postFamily, jdbcType=VARCHAR}
AND D.SHIFT_NO = #{shiftNo, jdbcType=VARCHAR}
AND D.ITEM_NO = #{itemNo, jdbcType=VARCHAR}
ORDER BY TO_DATE(REPLACE(D.AR_DATE_STR, '/', '-'), 'YYYY-MM-DD') DESC, HE.EMPID
